<span class="line"><span style="color:#C678DD;">    return</span><span style="color:#61AFEF;"> deepMerge</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">val1</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">val2</span><span style="color:#ABB2BF;">)</span></span>
